#include<bits/stdc++.h>
using namespace std;
int a[100005],b[100005];
int n;
void hebing(int l,int r){
	if(l>=r)return;
	int mid=(l+r)/2;
	int i=l,j=mid+1,tot=l;
//	cout<<l<<" "<<r<<" "<<mid<<endl;
	while(i<=mid&&j<=r){
		if(a[i]<=a[j])b[tot++]=a[i++];
		else b[tot++]=a[j++];
//		cout<<i<<" "<<j<<endl;
	}
	while(i<=mid){
		b[tot++]=a[i++];
//		cout<<i<<endl;
	}
	while(j<=r){
		b[tot++]=a[j++];
	//	cout<<j<<endl;
	}
	for(int k=l;k<=r;k++)a[k]=b[k];
}
void guibing(int l,int r){
	if(l<r){
		int mid=(l+r)/2;
		guibing(l,mid);
		guibing(mid+1,r);
		hebing(l,r);
	}
	
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i];
	guibing(1,n);
	for(int i=1;i<=n;i++)cout<<a[i]<<" ";
}
